51: export class LegalASTEngine {
52:   /**
53:    * Generates an empty, typed Document AST structure.
54:    */
55:   static createDocument(docType: string, jurisdiction: string, corpusVersion: string): DocumentAST {
56:     return {
57:       id: uuidv4(),
58:       type: "DOCUMENT",
59:       version: 1,
60:       metadata: {
61:         docType,
62:         jurisdiction,
63:         corpusVersion,
64:         lastCompiled: new Date().toISOString()
65:       },
66:       clauses: []
67:     };
68:   }
69: 
70:   /**
71:    * Compiles the AST tree back into raw display text (anonymized or raw).
72:    */
73:   static toText(node: DocumentAST | ClauseNode, redactPII: boolean = false): string {
74:     if (node.type === "CLAUSE") {
75:       return node.children
76:         .map((child) => {
77:           if (child.type === "VARIABLE") {
78:             return redactPII ? child.anonymizedValue : child.rawValue;
79:           }
80:           return child.text;
81:         })
82:         .join("");
83:     }
84: 
85:     return node.clauses.map((clause) => `${clause.title}\n${this.toText(clause, redactPII)}`).join("\n\n");
86:   }
87: 
88:   /**
89:    * Generates a structural JSON schema representation of the document for agent context ingestion.
90:    */
91:   static toAIContextSchema(doc: DocumentAST): string {
92:     const simplified = {
93:       id: doc.id,
94:       metadata: doc.metadata,
95:       structure: doc.clauses.map((c) => ({
96:         clause_id: c.id,
97:         clause_type: c.clauseType,
98:         is_mandatory: c.isMandatory,
99:         variables: c.children
100:           .filter((child): child is VariableNode => child.type === "VARIABLE")
101:           .map((v) => ({ key: v.key, type: v.valueType, token: v.anonymizedValue }))
102:       }))
103:     };
104:     return JSON.stringify(simplified, null, 2);
105:   }
